import { Box, Typography } from "@mui/material";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { Prism as SyntaxHighlighter } from "react-syntax-highlighter";
import { oneDark } from "react-syntax-highlighter/dist/esm/styles/prism";

const MarkdownWithCode: React.FC<{ children: string }> = ({ children }) => (
  <Box sx={{ wordBreak: "break-word" }}>
    <ReactMarkdown
      remarkPlugins={[remarkGfm]}
      components={{
        p: ({ children }) => (
          <Typography
            variant="body2"
            sx={{ lineHeight: 1.4, mb: 1 }}
            component="p">
            {children}
          </Typography>
        ),
        li: ({ children }) => (
          <li style={{ marginBottom: "0.25em", lineHeight: 1.4 }}>
            <Typography
              variant="body2"
              component="span">
              {children}
            </Typography>
          </li>
        ),

        code({ inline, className, children, ...props }: React.ComponentPropsWithoutRef<"code"> & { inline?: boolean }) {
          const match = /language-(\w+)/.exec(className || "");
          return !inline && match ? (
            <Box sx={{ overflowX: "auto", my: 1 }}>
              <SyntaxHighlighter
                language={match[1]}
                style={oneDark as any}
                PreTag="div"
                customStyle={{
                  whiteSpace: "pre",
                  padding: "1em",
                  margin: 0,
                  lineHeight: "1.4",
                }}
                wrapLongLines={false}
                {...props}>
                {String(children).replace(/\n$/, "")}
              </SyntaxHighlighter>
            </Box>
          ) : (
            <code
              className={className}
              style={{
                backgroundColor: "#333",
                padding: "0.2em 0.4em",
                borderRadius: 4,
              }}
              {...props}>
              {children}
            </code>
          );
        },
      }}>
      {children}
    </ReactMarkdown>
  </Box>
);

export default MarkdownWithCode;

import { Box, IconButton, Paper, Tooltip, Typography } from "@mui/material";
import { useAuthStore } from "../store/AuthStore";
import MarkdownWithCode from "./MarkdownWithCode";
import TypingIndicator from "./TypingIndicator";
import RefreshIcon from "@mui/icons-material/Refresh";
import DeleteIcon from "@mui/icons-material/Delete";
import PushPinIcon from "@mui/icons-material/PushPin";
import PushPinOutlinedIcon from "@mui/icons-material/PushPinOutlined";
import { useChatStore } from "../store/ChatStore";
import { chatModels } from "./ModelSelector";
import { Message } from "../database/AthenaDb";
import { useNotificationStore } from "../store/NotificationStore";

interface MessageBubbleProps {
  message: Message;
}

const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const { updateMessageContext, deleteMessage, sendMessage } = useChatStore();
  const { addNotification } = useNotificationStore();
  const { userName } = useAuthStore();

  const isAssistant = message.type === "assistant";

  const togglePin = async (): Promise<void> => {
    try {
      await updateMessageContext(message.id, !message.includeInContext);
    } catch (err) {
      console.error("Failed to update context pin:", err);
      const message = err instanceof Error ? err.message : String(err);
      addNotification("Failed to update context pin", message);
    }
  };

  const handleDelete = async (): Promise<void> => {
    try {
      await deleteMessage(message.id);
    } catch (err) {
      console.error("Failed to delete message:", err);
      const message = err instanceof Error ? err.message : String(err);
      addNotification("Failed to delete message", message);
    }
  };

  const getModelLabel = (id?: string): string => {
    return chatModels.find((m) => m.id === id)?.label ?? id ?? "Unknown model";
  };

  return (
    <Paper
      sx={{
        p: 2,
        width: "100%",
        borderRadius: 3,
        bgcolor: (theme): string | undefined => {
          if (message.failed) return theme.palette.error.main;
          if (message.type === "assistant") return theme.palette.assistant.main;
          if (message.type === "aiNote") return theme.palette.aiNote.main;
          return undefined;
        },
        color: (theme): string | undefined => {
          if (message.failed) return "white";
          if (message.type === "assistant") return theme.palette.assistant.contrastText;
          if (message.type === "aiNote") return theme.palette.aiNote.contrastText;
          return undefined;
        },
      }}>
      <Box sx={{ width: "100%" }}>
        <Box
          display="flex"
          justifyContent="space-between"
          mb={0.5}>
          <Typography
            variant="subtitle2"
            color="text.secondary">
            {message.type === "user" ? (userName ?? "You") : getModelLabel(message.model)}
          </Typography>

          <Box
            display="flex"
            alignItems="center">
            <Typography
              variant="caption"
              color="text.secondary"
              sx={{ mr: 1 }}>
              {`${message.totalCost.toFixed(3)} kr • ${new Intl.DateTimeFormat("sv-SE", {
                year: "numeric",
                month: "2-digit",
                day: "2-digit",
                hour: "2-digit",
                minute: "2-digit",
                hour12: false,
              }).format(new Date(message.created))}`}
            </Typography>

            <Tooltip title="Delete message">
              <IconButton
                size="small"
                onClick={(): void => { void handleDelete(); }}>
                <DeleteIcon />
              </IconButton>
            </Tooltip>

            <Tooltip title={message.includeInContext ? "Unpin from context" : "Pin to context"}>
              <IconButton
                size="small"
                onClick={(): void => { void togglePin(); }}>
                {message.includeInContext ? <PushPinIcon /> : <PushPinOutlinedIcon />}
              </IconButton>
            </Tooltip>
          </Box>
        </Box>

        <Box sx={{ overflowX: "auto" }}>
          {message.type === "aiNote" ? (
            <Typography
              variant="body2"
              fontStyle="italic"
              color="text.secondary">
              {getModelLabel(message.model)} stored a hidden note here.
            </Typography>
          ) : (
            <MarkdownWithCode>{message.content}</MarkdownWithCode>
          )}
        </Box>

        {isAssistant && message.content === "" && (
          <Box mt={1}>
            <TypingIndicator />
          </Box>
        )}

        {message.failed && (
          <Tooltip title="Retry">
            <IconButton
              onClick={(): void => { void sendMessage(message.content, message.topicId, message.id); }}
              color="inherit">
              <RefreshIcon />
            </IconButton>
          </Tooltip>
        )}
      </Box>
    </Paper>
  );
};

export default MessageBubble;

import React, { JSX, useEffect, useRef } from "react";
import { ListItem, Button, Fab } from "@mui/material";
import ArrowDownwardIcon from "@mui/icons-material/ArrowDownward";
import ScrollToBottom, { useScrollToBottom, useSticky } from "react-scroll-to-bottom";
import { css } from "@emotion/css";
import { useParams } from "react-router-dom";

import { useChatStore } from "../store/ChatStore";
import { useUiStore } from "../store/UiStore";
import MessageBubble from "./MessageBubble";
import { Message } from "../database/AthenaDb";

const FollowFab = (): JSX.Element | null => {
  const scrollToBottom = useScrollToBottom();
  const [sticky] = useSticky();
  if (sticky) return null;

  return (
    <Fab
      color="primary"
      size="small"
      sx={{
        position: "absolute",
        right: 20,
        bottom: 10,
        zIndex: 10,
        minHeight: 32,
        height: 32,
        width: 32,
        p: 0,
        bgcolor: "transparent",
        boxShadow: "none",
        color: "primary.main",
        "&:hover": {
          bgcolor: "primary.main",
          color: "#fff",
          boxShadow: 3,
        },
      }}
      onClick={(): void => scrollToBottom({ behavior: "smooth" })}>
      <ArrowDownwardIcon fontSize="small" />
    </Fab>
  );
};

const Pane: React.FC<{ messages: Message[] }> = ({ messages }) => {
  const { showAllMessages } = useUiStore();

  const scrollToBottom = useScrollToBottom();
  const [sticky] = useSticky();

  const last = messages[messages.length - 1];
  const sig = last ? `${last.id}:${last.content.length}` : "";

  const prevSigRef = useRef(sig);
  const wasStickyRef = useRef<boolean>(true);

  useEffect(() => {
    if (sig !== prevSigRef.current && wasStickyRef.current) {
      scrollToBottom({ behavior: "smooth" });
    }

    prevSigRef.current = sig;
    wasStickyRef.current = sticky;
  });

  return (
    <>
      {messages.map((m) => (
        <ListItem
          key={m.id}
          disableGutters>
          <MessageBubble
            message={
              m.type === "aiNote" && !showAllMessages ? { ...m, content: "⚠️ Assistant stored a hidden note here." } : m
            }
          />
        </ListItem>
      ))}

      <FollowFab />
    </>
  );
};

interface Props {
  messages: Message[];
}

const MessageList: React.FC<Props> = ({ messages }) => {
  const { topicId } = useParams();
  const { visibleMessageCount, increaseVisibleMessageCount } = useChatStore();

  const visible = messages.filter((m) => !m.isDeleted).slice(-visibleMessageCount);

  const ROOT = css({ height: "100%" });

  return (
    <ScrollToBottom
      key={topicId}
      className={ROOT}
      initialScrollBehavior="auto"
      scrollViewClassName="my-scroll-view"
      followButtonClassName={css({ display: "none" })}>
      {messages.length > visible.length && (
        <ListItem>
          <Button
            onClick={increaseVisibleMessageCount}
            fullWidth
            variant="outlined">
            Load older messages
          </Button>
        </ListItem>
      )}

      <Pane messages={visible} />
    </ScrollToBottom>
  );
};

export default MessageList;

import React from "react";
